}

__kernel void bpnn_layerforward_ocl(__global float *input_ocl,
                                    __global float *output_hidden_ocl,
                                    __global float *input_hidden_ocl,
                                    __global float *hidden_partial_sum,
                                    __local float *local_mem1,
                                    __local float *local_mem2,
                                    cl_int in,
                                    cl_int hid)
{
    int j = get_global_id(0);
    int block_id = get_global_id(1) / BLOCK_SIZE;
    int k_start = block_id * BLOCK_SIZE;
    int k_end = k_start + BLOCK_SIZE;

    if (j >= 1 && j <= hid) {
        float sum = 0.0f;

        for (int k = k_start; k < k_end && k <= in; k++) {
            int weight_idx = k * (hid + 1) + j;
            sum += input_hidden_ocl[weight_idx] * input_ocl[k];
        }

        hidden_partial_sum[block_id * hid + (j - 1)] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(__global float *hidden_delta_ocl,
                                      cl_int hid,
                                      __global float *input_ocl,
                                      cl_int in,
                                      __global float *input_hidden_ocl,
                                      __global float *input_prev_weights_ocl)
{
    int j = get_global_id(0);
    int k = get_global_id(1);

    if (j >= 1 && j <= hid && k <= in) {
        int weight_idx = k * (hid + 1) + j;
        float delta_val = hidden_delta_ocl[j];
        float ly_val = input_ocl[k];
