        float new_dw = (ETA * delta_val * ly_val) + (MOMENTUM * oldw_val);
        input_hidden_ocl[weight_idx] += new_dw;
        input_prev_weights_ocl[weight_idx] = new_dw;
    }
}

#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x)
{
    return (1.0f / (1.0f + exp(-x)));
}

kernel void bpnn_layerforward_ocl(global float* input,
                                   global float* output,
                                   global float* weights,
                                   global float* partial_sum,
                                   local float* local_mem,
                                   const int n1,
                                   const int n2)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= n2 || j < 1) return;

    float sum = 0.0f;

    for (int i = 0; i <= n1; i++) {
        sum += weights[i * (n2 + 1) + j] * input[i];
    }

    output[j] = squash(sum);

    if (k < BLOCK_SIZE && j <= n2) {
