__kernel void bpnn_adjust_weights_ocl(
    __global float *delta,
    cl_int hid,
    __global float *input,
    cl_int in,
    __global float *weights,
    __global float *old_weights
) {
    cl_int j = get_global_id(1) + 1;
    cl_int k = get_global_id(0);

    if (j <= hid && k <= in) {
        float new_dw = (ETA * delta[j] * input[k]) + (MOMENTUM * old_weights[k * (hid + 1) + j]);
        weights[k * (hid + 1) + j] += new_dw;
        old_weights[k * (hid + 1) + j] = new_dw;
    }
}

#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x)
{
    return (1.0f / (1.0f + exp(-x)));
}

kernel void bpnn_layerforward_ocl(
    global float *input_ocl,
    global float *output_hidden_ocl,
    global float *input_hidden_ocl,
    global float *hidden_partial_sum,
    local float *local_mem1,
    local float *local_mem2,
    const int in,
    const int hid)
{
    int j = get_global_id(0);
    int block_id = get_global_id(1);

    if (j >= hid + 1) return;

    float sum = 0.0f;

    for (int k = 0; k <= in; k++) {
        int idx = k * (hid + 1) + j;
        if (idx < (in + 1) * (hid + 1)) {
            sum += input_hidden_ocl[idx] * input_ocl[k];
        }
    }

    if (j > 0 && block_id == 0) {
        output_hidden_ocl[j] = squash(sum);
    }

    if (block_id < (in + 1) / BLOCK_SIZE && j > 0) {
        hidden_partial_sum[block_id * hid + (j - 1)] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(
    global float *hidden_delta_ocl,
    const int hid,
    global float *input_ocl,
    const int in,
    global float *input_hidden_ocl,
    global float *input_prev_weights_ocl)
{
    int j = get_global_id(0);
    int k = get_global_id(1);

    if (j < 1 || j > hid) return;
    if (k > in) return;

    int idx = k * (hid + 1) + j;
    if (idx >= (in + 1) * (hid + 1)) return;

    float delta = hidden_delta_ocl[j];
    float ly = (k == 0) ? 1.0f : input_ocl[k];
    float oldw = input_prev_weights_ocl[idx];

    float new_dw = (ETA * delta * ly) + (MOMENTUM * oldw);
    input_hidden_ocl[idx] += new_dw;
    input_prev_weights_ocl[idx] = new_dw;
}

