        int min = gpuResult_src[n];
        if (n > 0) {
            int left = gpuResult_src[n-1];
            min = (min <= left) ? min : left;
        }
        if (n < cols-1) {
            int right = gpuResult_src[n+1];
            min = (min <= right) ? min : right;
