// OpenCL kernel for streamcluster pgain operation

#define CACHE_LINE 512

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

// Kernel to compute gain for opening new center x
kernel void pgain_kernel(
    global Point_Struct* p,
    global float* coord,
    global float* work_mem,
    global int* center_table,
    global char* switch_membership,
    local float* local_coord,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int i = get_global_id(0);

    if (i >= num) return;

    // Load point coordinates into local memory
    for (int d = 0; d < dim; d++) {
        local_coord[d * THREADS_PER_BLOCK + get_local_id(0)] = coord[d * num + i];
    }

    // Compute distance from point i to center x
    float x_coord[dim];
    for (int d = 0; d < dim; d++) {
        x_coord[d] = coord[d * num + x];
    }

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = local_coord[d * THREADS_PER_BLOCK + get_local_id(0)] - x_coord[d];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        int ct = center_table[assign];
        if (ct >= 0 && ct < K) {
            work_mem[i * (K + 1) + ct] += current_cost - x_cost;
        }
    }
}

// Kernel to aggregate work_mem across points for center evaluation
kernel void pgain_aggregate_kernel(
    global float* work_mem,
    global int* center_table,
    global float* gl_lower,
    global char* is_center,
    const int num,
    const int K,
    const float z)
{
    int i = get_global_id(0);

    if (i >= num) return;

    if (is_center[i]) {
        int ct = center_table[i];
        if (ct >= 0 && ct < K) {
            float low = z;
            for (int j = 0; j < num; j++) {
                low += work_mem[j * (K + 1) + ct];
            }
            gl_lower[ct] = low;
        }
    }
}

// Kernel to update point assignments after center change
kernel void pgain_update_kernel(
    global Point_Struct* p,
    global float* coord,
